import fs from "node:fs";
import { runTrackSkill } from "../commands/trackSkill.js";
import { BITFAB_SKILLS } from "../skills.js";
// Matches `/bitfab:<skill>` (Claude) and `/bitfab-<skill>` (Cursor).
// The named `skill` group captures the canonical skill name used in analytics.
// Skill names come from BITFAB_SKILLS so adding a skill in one place flows
// through to detection automatically.
const SKILL_PATTERN = new RegExp(`^\\s*\\/bitfab[:-](?<skill>${BITFAB_SKILLS.join("|")})(?=\\s|$)`, "i");
/**
 * Extracts the skill name from a user prompt if it is a Bitfab slash command.
 * Returns null if the prompt is not a Bitfab skill invocation.
 */
export function extractSkillFromPrompt(prompt) {
    const match = prompt.match(SKILL_PATTERN);
    const raw = match?.groups?.skill?.toLowerCase();
    return BITFAB_SKILLS.includes(raw ?? "")
        ? raw
        : null;
}
function readHookInput() {
    try {
        const stdin = fs.readFileSync(0, "utf-8");
        if (!stdin.trim()) {
            return null;
        }
        return JSON.parse(stdin);
    }
    catch {
        return null;
    }
}
/**
 * Entry point for the UserPromptSubmit (Claude Code) / beforeSubmitPrompt
 * (Cursor) hook. Reads the hook payload from stdin, detects Bitfab skill
 * invocations, and emits a server-side `api:plugin_skill_invoke` analytics event via
 * {@link runTrackSkill}. Never throws — telemetry must never block prompt
 * submission.
 */
export async function runUserPromptSubmit(pluginVersion, platform) {
    const input = readHookInput();
    if (!input?.prompt) {
        return;
    }
    const skillName = extractSkillFromPrompt(input.prompt);
    if (!skillName) {
        return;
    }
    await runTrackSkill(skillName, pluginVersion, platform);
}
